package com.vycepay.admin.api.v1;
import java.util.*; import com.vycepay.admin.application.service.*; import com.vycepay.common.api.*; import jakarta.servlet.http.HttpServletRequest; import org.springframework.http.*; import org.springframework.security.access.prepost.PreAuthorize; import org.springframework.web.bind.annotation.*;
/** Audit log APIs for customer activity and admin action trails. */
@RestController @RequestMapping("/api/admin/v1/audit-log") @PreAuthorize("hasAuthority('PERM_audit_log:view')")
public class AuditLogController{private final AdminReadService r; private final CsvExportService csv; private final RateLimitService rateLimitService; public AuditLogController(AdminReadService r,CsvExportService csv,RateLimitService rateLimitService){this.r=r;this.csv=csv;this.rateLimitService=rateLimitService;} @GetMapping public ResponseEntity<ApiSuccessResponse<Map<String,Object>>> list(@RequestParam(required=false)Integer page,@RequestParam(required=false)Integer size,@RequestParam(required=false)String action,@RequestParam(defaultValue="customer")String source){return ResponseEntity.ok(ApiSuccessResponses.ok("AUDIT_OK","Audit log","admin".equals(source)?r.adminAuditLog(page,size,action):r.auditLog(page,size,action)));} @GetMapping("/export") public ResponseEntity<String> export(HttpServletRequest req){rateLimitService.check("export",req);return ResponseEntity.ok().header(HttpHeaders.CONTENT_DISPOSITION,"attachment; filename=audit-log.csv").contentType(MediaType.TEXT_PLAIN).body(csv.auditLog(req));}}
